class Solution {
    public int findBestValue(int[] arr, int target) {
        Arrays.sort(arr);
        int n = arr.length;
        int[] prefixSum = new int[n + 1];
        for (int i = 0; i < n; i++) {
            prefixSum[i + 1] = prefixSum[i] + arr[i];
        }
        int closest = Integer.MAX_VALUE;
        int ans = 0;
        for (int i = 0; i < n; i++) {
            int val = (target - prefixSum[i]) / (n - i);
            int sum1 = prefixSum[i] + val * (n - i);
            int sum2 = prefixSum[i] + (val + 1) * (n - i);
            if (Math.abs(sum1 - target) <= Math.abs(sum2 - target)) {
                if (Math.abs(sum1 - target) < Math.abs(closest - target)) {
                    closest = sum1;
                    ans = val;
                } else if (Math.abs(sum1 - target) == Math.abs(closest - target)) {
                    ans = Math.min(ans, val);
                }
            } else {
                if (Math.abs(sum2 - target) < Math.abs(closest - target)) {
                    closest = sum2;
                    ans = val + 1;
                } else if (Math.abs(sum2 - target) == Math.abs(closest - target)) {
                    ans = Math.min(ans, val + 1);
                }
            }
        }
        return ans;
    }
}
